79|def layer_data_to_json(slicer, max_sample=64):
80|    """Convert slicer layers to JSON for Three.js filled-polygon rendering.
81|
82|    Each layer's paths: the first closed path is the outer contour,
83|    subsequent closed paths are holes.
84|    Renders each layer as a filled polygon with holes subtracted.
85|    """
86|    # Sample evenly
87|    total = len(slicer.layers)
88|    step = max(1, total // max_sample)
89|    sampled_indices = list(range(0, total, step))[:max_sample]
90|
91|    layers_json = []
92|    for idx in sampled_indices:
93|        layer = slicer.layers[idx]
94|        if not layer.paths:
95|            continue
96|
97|        z = round(layer.paths[0].points[0].z, 1) if layer.paths[0].points else 0
98|
99|        outer = []
100|        holes = []
101|        for path in layer.paths:
102|            pts = [(round(p.x, 1), round(p.y, 1)) for p in path.points if p is not None]
103|            if len(pts) < 3:
104|                continue
105|            # First closed path = outer, rest closed = holes
106|            if not outer and path.is_closed:
107|                outer = pts
108|            elif path.is_closed:
109|                holes.append(pts)
110|
111|        if outer:
112|            layers_json.append({
113|                "z": z,
114|                "outer": outer,
115|                "holes": holes,
116|            })
